mapper.select:
SELECT i.id, i.title, i.description, i.category_id, c.name AS category_name, c.icon AS category_icon, i.location_id, l.name AS location_name, i.publish_date, i.expiry_date, i.status, i.owner_type, i.user_id, u.real_name AS user_name, i.phone, i.views, i.created_at FROM lost_found_item i LEFT JOIN sys_category c ON i.category_id = c.id LEFT JOIN sys_location l ON i.location_id = l.id LEFT JOIN sys_user u ON i.user_id = u.id AND u.is_deleted = 0 WHERE i.is_deleted = 0
AND (i.title LIKE CONCAT('%', #{keyword}, '%') OR i.description LIKE CONCAT('%', #{keyword}, '%'))
AND i.category_id = #{categoryId}
AND i.location_id = #{locationId}
AND i.status = #{status}
AND i.owner_type = #{ownerType}
AND i.user_id = #{userId}
ORDER BY i.created_at DESC

mapper.update:
UPDATE lost_found_item
SET is_deleted = 1, updated_at = NOW()
WHERE id = #{itemId}
